files.content:
.mrg-time-field {
  color: var(--mrg-semantic-color-foreground-primary);
  display: grid;
  font-family: var(--mrg-semantic-font-family-prose);
  gap: var(--mrg-semantic-space-stack-xs);
  inline-size: 100%;
  min-inline-size: 0;
}

.mrg-time-field-control {
  background: var(--mrg-semantic-color-background-canvas);
  border: var(--mrg-semantic-border-width-strong) solid var(--mrg-semantic-color-border-interactive);
  border-radius: var(--mrg-semantic-radius-control);
  box-sizing: border-box;
  color: inherit;
  font: inherit;
  inline-size: 100%;
  min-block-size: var(--mrg-semantic-density-control-height);
  min-inline-size: 0;
  padding: var(--mrg-semantic-density-control-padding-block)
    var(--mrg-semantic-density-control-padding-inline);
}

.mrg-time-field-control:focus-visible {
  box-shadow: 0 0 0 var(--mrg-semantic-focus-width)
    var(--mrg-semantic-color-focus-contrast-background);
  outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
  outline-offset: var(--mrg-semantic-focus-offset);
}

.mrg-time-field-control:invalid {
  border-color: var(--mrg-semantic-color-status-danger-border);
}

.mrg-time-field-control:disabled {
  background: var(--mrg-semantic-color-background-disabled);
  border-color: var(--mrg-semantic-color-border-disabled);
  color: var(--mrg-semantic-color-foreground-disabled);
}

.mrg-time-field [data-slot="time-field-zone"] {
  border-inline-start: var(--mrg-semantic-border-width-emphasis) solid
    var(--mrg-semantic-color-brand-violet);
  color: var(--mrg-semantic-color-foreground-muted);
  font-size: var(--mrg-semantic-font-size-label);
  overflow-wrap: anywhere;
  padding-inline-start: var(--mrg-semantic-space-inline-sm);
}

@media (pointer: coarse) {
  .mrg-time-field-control {
    min-block-size: var(--mrg-semantic-size-target-preferred);
  }
}

@media (forced-colors: active) {
  .mrg-time-field-control {
    background: Field;
    border-color: FieldText;
    color: FieldText;
  }

  .mrg-time-field-control:focus-visible {
    box-shadow: none;
    outline-color: Highlight;
  }

  .mrg-time-field [data-slot="time-field-zone"] {
    border-color: Highlight;
    color: CanvasText;
  }
}

"use client";

import { forwardRef, useId, useMemo, type InputHTMLAttributes, type ReactNode } from "react";

import {
  mergeTemporalRefs,
  nativeTemporalInputProps,
  useNativeTemporalControl,
} from "../date-field/date-time-utils";
import "./time-field.css";

export interface TimeFieldProps extends Omit<
  InputHTMLAttributes<HTMLInputElement>,
  "defaultValue" | "onChange" | "type" | "value"
> {
  /** Initial native time value for uncontrolled use and form reset. */
  readonly defaultValue?: string;
  /** Receives the original native time-input change event after state is updated. */
  readonly onChange?: InputHTMLAttributes<HTMLInputElement>["onChange"];
  /** Reports native time edits and form-reset restoration. */
  readonly onValueChange?: (value: string) => void;
  /** Adds linked time-zone context; `false` removes its UI and accessibility output. */
  readonly showTimeZoneContext?: boolean;
  /** Custom time-zone context content or renderer used when context is enabled. */
  readonly timeZoneContext?: ReactNode | ((timeZone: string) => ReactNode);
  /** Time-zone identifier shown in context, falling back to the browser-resolved zone. */
  readonly timeZone?: string | undefined;
  /** Controlled native time value; pair with `onValueChange`. */
  readonly value?: string;
}

export const TimeField = forwardRef<HTMLInputElement, TimeFieldProps>(function TimeField(
  {
    "aria-describedby": ariaDescribedBy,
    className,
    defaultValue = "",
    onChange,
    onValueChange,
    showTimeZoneContext = false,
    timeZone,
    timeZoneContext,
    value,
    ...nativeProps
  },
  forwardedRef,
) {
  const generatedId = useId().replaceAll(":", "");
  const control = useNativeTemporalControl({ defaultValue, onChange, onValueChange, value });
  const context = useMemo(() => {
    if (!showTimeZoneContext) return null;
    const resolvedZone = timeZone ?? Intl.DateTimeFormat().resolvedOptions().timeZone;
    return typeof timeZoneContext === "function"
      ? timeZoneContext(resolvedZone)
      : (timeZoneContext ?? `Time zone: ${resolvedZone}`);
  }, [showTimeZoneContext, timeZone, timeZoneContext]);
  const contextId = context === null ? undefined : `mrg-time-field-${generatedId}-zone`;

  return (
    <span className="mrg-time-field" data-time-zone={contextId === undefined ? undefined : true}>
      <input
        {...nativeTemporalInputProps("time")}
        {...nativeProps}
        aria-describedby={[ariaDescribedBy, contextId].filter(Boolean).join(" ") || undefined}
        className={
          className === undefined ? "mrg-time-field-control" : `mrg-time-field-control ${className}`
        }
        data-slot="time-field"
        onChange={control.onChange}
        ref={mergeTemporalRefs(control.inputRef, forwardedRef)}
        type="time"
        value={control.value}
      />
      {contextId === undefined ? null : (
        <span data-slot="time-field-zone" id={contextId}>
          {context}
        </span>
      )}
    </span>
  );
});

TimeField.displayName = "TimeField";
